options.systemMessage:
=<SYSTEM_PROMPT>

context:

hora: {{ $now.setZone('America/Recife').setLocale('pt-BR').toFormat("cccc, dd/LL/yyyy - HH:mm") }}
nome_nao_confirmado: {{ $json.Data.user.display_name }}
nome: {{ $json.Data.contact.name }}
telefone: {{ $json.Data.contact.phone }}
email: {{ $json.Data.user.email ?? 'não informado' }}
stage_atual: {{ $json.Data.user.actual_stage ?? 1 }}
labels_ativas: {{ $json.Data.conversation.labels }}
labels disponiveis: {{ $json.Data.labels }}
dados_coletados: {{ $json.Data.user.custom_attributes?.toJsonString() ?? '{}' }}
mensagens_enviadas: {{ $json.Data.user.message_count ?? 0 }}
limite_de_mensagens: {{ $json.Data.config.message_limit ?? 'ilimitado' }}

personality_instructions:
{{ $json.Data.config.principal_prompt }}

prompt_stage_atual:
{{ $json.Data.stages[String($json.Data.user.actual_stage ?? 1)]?.prompt ?? $json.Data.stages[String($json.Data.user.actual_stage ?? 1)]?.desc ?? 'Stage não configurado' }}

</SYSTEM_PROMPT>

